effect.script:
function animate(env,el,p) {
    let t = env.time;
    let m
    if( p.type == 0 ) {
        m = Math.sin(((t * env.duration * p.freq)+p.phase) * 3.14159)
    } else {
        m = AM.triangle(((t * env.duration * p.freq)+p.phase) / 2.0)
    }
    let range = (p.maxsize - p.minsize);
    let ds = (range * ((m+1.0)/2.0) ) + p.minsize;
    //AM.log("EffectsPulse(A) " + el.transform.scale.x + "," + el.transform.scale.y + "   ds=" + ds + " range=" + range + " m=" + m + " p.minsize=" + p.minsize + " p.maxsize=" + p.maxsize + " dur=" + env.duration + " freq=" + p.freq + " t=" + t);
    el.transform.scale.x *= ds;
    el.transform.scale.y *= ds;
    //AM.log("EffectsPulse(B) " + el.transform.scale.x + "," + el.transform.scale.y);
    return el;
}
